import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # State: (lo, hi) with lo <= 0 <= hi, coverage = hi - lo
    # Use dict: lo -> min_hi for Pareto front
    states = {0: 0}  # lo=0, hi=0

    for d in a:
        new_states = {}
        for lo, hi in states.items():
            for sign in [1, -1]:
                if sign == 1:
                    nlo = min(lo - d, 0)
                    nhi = max(hi - d, 0)
                else:
                    nlo = min(lo + d, 0)
                    nhi = max(hi + d, 0)
                if nlo not in new_states or new_states[nlo] > nhi:
                    new_states[nlo] = nhi
        # Pareto pruning: sort by lo ascending, keep only those where hi is non-increasing
        sorted_lo = sorted(new_states.keys())
        pareto = {}
        min_hi = float('inf')
        for lo in sorted_lo:
            hi = new_states[lo]
            if hi < min_hi:
                min_hi = hi
                pareto[lo] = hi
        states = pareto

    print(min(hi - lo for lo, hi in states.items()))

t = int(input())
for _ in range(t):
    solve()

